+/// Build a Laguerre series from roots.
+pub fn lagfromroots(roots: &[f64]) -> Vec<f64> {
+    if roots.is_empty() {
+        return vec![1.0];
+    }
+    // (x - r) in Laguerre basis: L_0=1, L_1=1-x → x = L_0 - L_1
+    // So (x - r) = (1-r)*L_0 + (-1)*L_1 = [1.0 - r, -1.0]
+    let mut result = vec![1.0 - roots[0], -1.0];
